import { Request, Response } from 'express';
import { CheckoutHandlerConfig } from '@dodopayments/core/checkout';
import { ClientOptions } from 'dodopayments';
import { WebhookHandlerConfig } from '@dodopayments/core/webhook';

declare function checkoutHandler(config: CheckoutHandlerConfig): (req: Request, res: Response) => Response<any, Record<string, any>> | Promise<Response<any, Record<string, any>>>;

type CustomerPortalConfig = Pick<ClientOptions, "environment" | "bearerToken">;
declare const CustomerPortal: ({ bearerToken, environment, }: CustomerPortalConfig) => (req: Request, res: Response) => Promise<void | Response<any, Record<string, any>>>;

declare const Webhooks: ({ webhookKey, ...eventHandlers }: WebhookHandlerConfig) => (req: Request, res: Response) => Promise<Response<any, Record<string, any>>>;

export { CustomerPortal, Webhooks, checkoutHandler };
export type { CustomerPortalConfig };
